        self.assertEqual(responses, ["4", "8"])

    def test_tokenize_prompt_and_output_pads_labels_and_masks_response_tokens(self):
        tokenizer = FakeTokenizer(
            {
                "p1": [11, 12],
                "r1": [21, 22, 23],
                "p2": [13],
                "r2": [24],
            }
        )

        inputs, labels, masks = self.train.tokenize_prompt_and_output(
            ["p1", "p2"],
            ["r1", "r2"],
